sql:
SELECT COUNT(*) AS active_team_count
FROM user_teams
WHERE user_id = 0 AND is_activated = 1;

SELECT team_name, captain_id, vice_captain_id, budget
FROM user_teams
WHERE user_team_id = 0;

SELECT SUM(ut.value) AS total_value
FROM user_teams ut
WHERE ut.is_activated = 1;

SELECT AVG(ut.value) AS average_team_value
FROM user_teams ut
WHERE ut.is_activated = 1;
